			cxPropFieldKey : Lyte.attr("string", {"default": ""}),//No I18n
			cxPropInfoTooltip: Lyte.attr("string", {"default": ""}), //NO I18n
			cxPropLabelClass: Lyte.attr("string", {"default": ""}), //NO I18n

			/*generic crux element warning properties*/
